pub struct WasmExtractionOutput {
    results: Vec<WasmExtractionResult>,
    errors: Vec<WasmExtractionErrorItem>,
    summary: WasmExtractionSummary,
    crawl_final_urls: Vec<String>,
    crawl_redirect_count: usize,
    crawl_unique_normalized_urls: Vec<String>,
}

#[wasm_bindgen]
impl WasmExtractionOutput {
    #[allow(non_snake_case)]
    #[wasm_bindgen(constructor)]
    pub fn new(
        results: Option<Vec<WasmExtractionResult>>,
        errors: Option<Vec<WasmExtractionErrorItem>>,
        summary: Option<WasmExtractionSummary>,
        crawlFinalUrls: Option<Vec<String>>,
        crawlRedirectCount: Option<usize>,
        crawlUniqueNormalizedUrls: Option<Vec<String>>,
    ) -> WasmExtractionOutput {
        WasmExtractionOutput {
            results: results.unwrap_or_default(),
            errors: errors.unwrap_or_default(),
            summary: summary.unwrap_or_default(),
            crawl_final_urls: crawlFinalUrls.unwrap_or_default(),
            crawl_redirect_count: crawlRedirectCount.unwrap_or_default(),
            crawl_unique_normalized_urls: crawlUniqueNormalizedUrls.unwrap_or_default(),
        }
    }

    #[wasm_bindgen]
    #[allow(clippy::should_implement_trait)]
    pub fn default() -> WasmExtractionOutput {
        <WasmExtractionOutput as ::core::default::Default>::default()
    }

    #[wasm_bindgen(getter)]
    pub fn results(&self) -> Vec<WasmExtractionResult> {
        self.results.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_results(&mut self, value: Vec<WasmExtractionResult>) {
        self.results = value;
    }

    #[wasm_bindgen(getter)]
    pub fn errors(&self) -> Vec<WasmExtractionErrorItem> {
        self.errors.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_errors(&mut self, value: Vec<WasmExtractionErrorItem>) {
        self.errors = value;
    }

    #[wasm_bindgen(getter)]
    pub fn summary(&self) -> WasmExtractionSummary {
        self.summary.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_summary(&mut self, value: WasmExtractionSummary) {
        self.summary = value;
    }

    #[wasm_bindgen(getter, js_name = "crawlFinalUrls")]
    pub fn crawl_final_urls(&self) -> Vec<String> {
        self.crawl_final_urls.clone()
    }

    #[wasm_bindgen(setter, js_name = "crawlFinalUrls")]
    pub fn set_crawl_final_urls(&mut self, value: Vec<String>) {
        self.crawl_final_urls = value;
    }

    #[wasm_bindgen(getter, js_name = "crawlRedirectCount")]
    pub fn crawl_redirect_count(&self) -> usize {
        self.crawl_redirect_count
    }

    #[wasm_bindgen(setter, js_name = "crawlRedirectCount")]
    pub fn set_crawl_redirect_count(&mut self, value: usize) {
        self.crawl_redirect_count = value;
    }

    #[wasm_bindgen(getter, js_name = "crawlUniqueNormalizedUrls")]
    pub fn crawl_unique_normalized_urls(&self) -> Vec<String> {
        self.crawl_unique_normalized_urls.clone()
    }

    #[wasm_bindgen(setter, js_name = "crawlUniqueNormalizedUrls")]
    pub fn set_crawl_unique_normalized_urls(&mut self, value: Vec<String>) {
        self.crawl_unique_normalized_urls = value;
    }

    /// Build an output containing one successful result.
    #[wasm_bindgen]
    pub fn single(result: WasmExtractionResult) -> WasmExtractionOutput {
        let result_core: xberg::ExtractionResult = result.into();

        xberg::ExtractionOutput::single(result_core).into()
    }
}

