/// Extract content from a single bytes or URI input.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen]
pub async fn extract(input: JsValue, config: JsValue) -> Result<WasmExtractionOutput, JsValue> {
    let input_core: xberg::ExtractInput = if input.is_undefined() {
        xberg::ExtractInput::default()
    } else {
        serde_wasm_bindgen::from_value::<xberg::ExtractInput>(input).map_err(|e| JsValue::from_str(&e.to_string()))?
    };
    let config_core: xberg::ExtractionConfig = if config.is_undefined() {
        xberg::ExtractionConfig::default()
    } else {
        serde_wasm_bindgen::from_value::<xberg::ExtractionConfig>(config)
            .map_err(|e| JsValue::from_str(&e.to_string()))?
    };
    let result = xberg::extract(input_core, &config_core)
        .await
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmExtractionOutput::from(result))
}

/// Extract content from multiple bytes or URI inputs.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "extractBatch")]
pub async fn extract_batch(inputs: Vec<WasmExtractInput>, config: JsValue) -> Result<WasmExtractionOutput, JsValue> {
    let inputs_core: Vec<xberg::ExtractInput> = inputs.into_iter().map(Into::into).collect();
    let config_core: xberg::ExtractionConfig = if config.is_undefined() {
        xberg::ExtractionConfig::default()
    } else {
        serde_wasm_bindgen::from_value::<xberg::ExtractionConfig>(config)
            .map_err(|e| JsValue::from_str(&e.to_string()))?
    };
    let result = xberg::extract_batch(inputs_core, &config_core)
        .await
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmExtractionOutput::from(result))
}

/// Detect MIME type from raw file bytes.
///
/// Uses magic byte signatures to detect file type from content.
/// Falls back to `infer` crate for comprehensive detection.
///
/// For ZIP-based files, inspects contents to distinguish Office Open XML
/// formats (DOCX, XLSX, PPTX) from plain ZIP archives.
///
/// # Arguments
///
/// * `content` - Raw file bytes
///
/// # Returns
///
/// The detected MIME type string.
///
/// # Errors
///
/// Returns `XbergError.UnsupportedFormat` if MIME type cannot be determined.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "detectMimeTypeFromBytes")]
pub fn detect_mime_type_from_bytes(content: Vec<u8>) -> Result<String, JsValue> {
    let result = xberg::detect_mime_type_from_bytes(&content).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// Get file extensions for a given MIME type.
///
/// Returns all known file extensions that map to the specified MIME type.
///
/// # Arguments
///
/// * `mime_type` - The MIME type to look up
///
/// # Returns
///
/// A vector of file extensions (without leading dot) for the MIME type.
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "getExtensionsForMime")]
pub fn get_extensions_for_mime(mime_type: String) -> Result<Vec<String>, JsValue> {
    let result = xberg::get_extensions_for_mime(&mime_type).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// List all supported document formats.
///
/// Returns every file extension Xberg recognizes together with its
/// corresponding MIME type, derived from the central format registry.
/// Formats that have no registered file extension (such as source code,
/// which is detected dynamically) are not included.
///
/// The list is sorted alphabetically by file extension.
///
/// # Returns
///
/// A vector of `SupportedFormat` entries sorted by extension.
///
/// # Example
#[wasm_bindgen(js_name = "listSupportedFormats")]
pub fn list_supported_formats() -> Vec<WasmSupportedFormat> {
    xberg::list_supported_formats().into_iter().map(Into::into).collect()
}

/// Detect QR codes in the bytes of an `ExtractedImage`.
///
/// `format_hint` is currently unused — the `image` crate auto-detects the
/// container format from magic bytes — but the parameter is retained so future
/// backends (e.g. a WebP-via-`webp-decoder` variant) can use it without an API
/// break.
///
/// Returns an empty vector on any of:
///
/// - Empty input.
/// - Image-decode failure.
/// - No QR grids detected.
/// - All detected grids fail to decode.
///
/// Successfully decoded QR codes carry their payload, a confidence of `1.0`
/// (rqrr does not expose per-grid confidence; a successful decode is treated
/// as high-confidence by convention), and the pixel-space bounding box derived
/// from the four corner points of the grid.
#[wasm_bindgen(js_name = "detectQrCodes")]
pub fn detect_qr_codes(image_bytes: Vec<u8>, _format_hint: Option<String>) -> Vec<WasmQrCode> {
    xberg::extractors::qr::detect_qr_codes(&image_bytes, _format_hint.as_deref())
        .into_iter()
        .map(Into::into)
        .collect()
}

