/// Run page classification against an extraction result.
///
/// Mutates `result.page_classifications` with one entry per non-empty page and
/// appends every LLM call's usage to `result.llm_usage`.
///
/// # Errors
///
/// Returns the first error encountered when rendering the prompt or calling the
/// LLM. Partially produced classifications are discarded so callers do not see
/// a half-populated vector.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "classifyPages")]
pub async fn classify_pages(result: JsValue, config: JsValue) -> Result<(), JsValue> {
    let mut result_core: xberg::ExtractionResult = if result.is_undefined() {
        xberg::ExtractionResult::default()
    } else {
        serde_wasm_bindgen::from_value::<xberg::ExtractionResult>(result)
            .map_err(|e| JsValue::from_str(&e.to_string()))?
    };
    let config_core: xberg::PageClassificationConfig = if config.is_undefined() {
        return Err(JsValue::from_str("config is required"));
    } else {
        serde_wasm_bindgen::from_value::<xberg::PageClassificationConfig>(config)
            .map_err(|e| JsValue::from_str(&e.to_string()))?
    };
    let result = xberg::text::classification::classify_pages(&mut result_core, &config_core)
        .await
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// Classify a single piece of text without requiring an `ExtractionResult`.
